/**
 * Focused tests for adminRateLimit middleware behavior.
 */

import { NextFunction, Response } from 'express';

import { AuthRequest } from '../../middleware/auth';
import { adminRateLimit } from '../../middleware/adminAuth';
import {
  AdminSecurityLogService,
  SecurityEventType,
} from '../../services/admin/AdminSecurityLogService';
import { cache } from '../../utils/redis';

jest.mock('../../services/admin/AdminSecurityLogService', () => ({
  AdminSecurityLogService: {
    logEvent: jest.fn(),
  },
  SecurityEventType: {
    API_RATE_LIMIT_EXCEEDED: 'API_RATE_LIMIT_EXCEEDED',
  },
}));

jest.mock('../../utils/logger', () => ({
  __esModule: true,
  default: {
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
    info: jest.fn(),
  },
  logger: {
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
    info: jest.fn(),
  },
}));

jest.mock('../../utils/redis', () => ({
  cache: {
    get: jest.fn(),
    set: jest.fn(),
  },
}));

describe('adminRateLimit middleware', () => {
  let mockReq: Partial<AuthRequest>;
  let mockRes: Partial<Response>;
  let mockNext: NextFunction;
  let jsonMock: jest.Mock;
  let statusMock: jest.Mock;
  let setHeaderMock: jest.Mock;

  beforeEach(() => {
    jest.clearAllMocks();

    jsonMock = jest.fn();
    statusMock = jest.fn().mockReturnThis();
    setHeaderMock = jest.fn();

    mockReq = {
      user: { id: 'admin-user-1', username: 'admin', role: 'admin' },
      method: 'GET',
      path: '/api/v2/admin/example',
      headers: {},
      ip: '127.0.0.1',
    };
    mockRes = {
      status: statusMock,
      json: jsonMock,
      setHeader: setHeaderMock,
    };
    mockNext = jest.fn();

    (cache.get as jest.Mock).mockResolvedValue(null);
    (cache.set as jest.Mock).mockResolvedValue(true);
  });

  it('should pass through when request has no authenticated user', async () => {
    const middleware = adminRateLimit();
    mockReq.user = undefined;

    await middleware(mockReq as AuthRequest, mockRes as Response, mockNext);

    expect(mockNext).toHaveBeenCalled();
    expect(cache.get).not.toHaveBeenCalled();
    expect(cache.set).not.toHaveBeenCalled();
  });

  it('should allow request under limit and set rate-limit headers', async () => {
    const middleware = adminRateLimit(2, 60000);

    await middleware(mockReq as AuthRequest, mockRes as Response, mockNext);

    expect(mockNext).toHaveBeenCalled();
    expect(statusMock).not.toHaveBeenCalled();
    expect(setHeaderMock).toHaveBeenCalledWith('X-RateLimit-Limit', '2');
    expect(setHeaderMock).toHaveBeenCalledWith('X-RateLimit-Remaining', '1');
    expect(setHeaderMock).toHaveBeenCalledWith('X-RateLimit-Reset', expect.any(String));
    expect(cache.get).toHaveBeenCalledWith('admin:rate-limit:admin-user-1');
    expect(cache.set).toHaveBeenCalledWith(
      'admin:rate-limit:admin-user-1',
      expect.objectContaining({ count: 1 }),
      expect.any(Number)
    );
  });

  it('should return 429 when distributed cache record exceeds limit', async () => {
    const middleware = adminRateLimit(2, 60000);
    (cache.get as jest.Mock).mockResolvedValue({
      count: 2,
      resetAt: Date.now() + 60000,
    });

    await middleware(mockReq as AuthRequest, mockRes as Response, mockNext);

    expect(mockNext).not.toHaveBeenCalled();
    expect(statusMock).toHaveBeenCalledWith(429);
    expect(jsonMock).toHaveBeenCalledWith(
      expect.objectContaining({
        message: 'Too many requests',
        retryAfter: expect.any(Number),
      })
    );
    expect(AdminSecurityLogService.logEvent).toHaveBeenCalledWith(
      SecurityEventType.API_RATE_LIMIT_EXCEEDED,
      'admin-user-1',
      'Admin API rate limit exceeded',
      'failure',
      expect.objectContaining({ resource: 'admin_api' })
    );
  });

  it('should fall back to local store when shared cache is unavailable', async () => {
    const middleware = adminRateLimit(1, 60000);
    mockReq.user = { id: 'admin-fallback-1', username: 'admin', role: 'admin' };

    (cache.get as jest.Mock).mockResolvedValue(null);
    (cache.set as jest.Mock).mockResolvedValue(false);

    await middleware(mockReq as AuthRequest, mockRes as Response, mockNext);
    expect(mockNext).toHaveBeenCalledTimes(1);

    mockNext = jest.fn();

    // No shared value returned, so second pass only blocks if local fallback persisted.
    (cache.get as jest.Mock).mockResolvedValueOnce(null);

    await middleware(mockReq as AuthRequest, mockRes as Response, mockNext);

    expect(mockNext).not.toHaveBeenCalled();
    expect(statusMock).toHaveBeenCalledWith(429);
  });
});
